composeOverride:
# Generated by McHarbor App Store
services:
  {{serviceName}}:
    image: {{image}}
    container_name: {{containerName}}
    restart: unless-stopped
{{ports}}
{{volumes}}
{{environment}}
    command:
      - --hass-websocket-uri
      - {{env.HASS_WEBSOCKET_URI}}
      - --hass-token
      - {{env.HASS_TOKEN}}
      - --custom-sentences-dir
      - /custom-sentences
      - --retrain-on-start
